from pathlib import Path
import json
import hashlib

ROOT = Path(".")

IGNORE = {
    ".git",
    ".venv",
    "venv",
    "__pycache__",
    "node_modules",
    "dist",
    "build",
    ".pytest_cache"
}

MAX_CONTENT = 50000

data = {
    "root": str(ROOT.resolve()),
    "directories": [],
    "files": []
}


def sha1_file(path):
    try:
        h = hashlib.sha1()

        with open(path, "rb") as f:

            while True:
                b = f.read(65536)

                if not b:
                    break

                h.update(b)

        return h.hexdigest()

    except:
        return None


for d in ROOT.rglob("*"):

    if any(x in d.parts for x in IGNORE):
        continue

    if d.is_dir():

        data["directories"].append(
            str(d)
        )

for f in ROOT.rglob("*"):

    if any(x in f.parts for x in IGNORE):
        continue

    if not f.is_file():
        continue

    item = {
        "path": str(f),
        "name": f.name,
        "suffix": f.suffix.lower(),
        "size": f.stat().st_size,
        "sha1": sha1_file(f)
    }

    try:

        txt = f.read_text(
            encoding="utf-8",
            errors="ignore"
        )

        item["content"] = txt[:MAX_CONTENT]

    except:

        item["content"] = "<binary>"

    data["files"].append(item)

Path(
    "TAPOS_FORENSIC_FULL.json"
).write_text(
    json.dumps(
        data,
        ensure_ascii=False,
        indent=2
    ),
    encoding="utf-8"
)

print()
print("=" * 60)
print("EXPORTAÇÃO TAPOS FINALIZADA")
print("Arquivo: TAPOS_FORENSIC_FULL.json")
print("Diretórios:", len(data["directories"]))
print("Arquivos:", len(data["files"]))
print("=" * 60)

